/* ADC 驱动与滤波层的抽象接口 */

typedef struct {
    uint32_t (*read_raw)(void);
    void     (*init)(uint32_t freq_hz);
} adc_driver_t;

typedef struct {
    const adc_driver_t *drv;
    uint32_t            samples_per_result;
    uint32_t            accumulator;
    uint32_t            count;
} oversampler_t;

void oversampler_init(oversampler_t *os,
                      const adc_driver_t *drv,
                      uint32_t ratio) {
    os->drv = drv;
    os->samples_per_result = ratio;
    os->accumulator = 0;
    os->count = 0;
}

uint32_t oversampler_read(oversampler_t *os) {
    os->accumulator += os->drv->read_raw();
    os->count++;
    if (os->count >= os->samples_per_result) {
        uint32_t result = os->accumulator / os->count;
        os->accumulator = 0;
        os->count = 0;
        return result;
    }
    return 0xFFFFFFFF;
}

/* ADC 校准与偏移修正 - STM32 HAL */

#define ADC_REF_VALUE     4095U

static int32_t g_offset_calib = 0;

/* 执行 ADC 自校准，必须在 ADC 关闭时调用 */
HAL_StatusTypeDef adc_self_calibrate(ADC_HandleTypeDef *hadc) {
    HAL_ADC_Stop(hadc);
    HAL_ADCEx_Calibration_Start(hadc, ADC_SINGLE_ENDED);
    return HAL_ADC_Start(hadc);
}

/* 测量内部偏移：短接 IN+ 和 IN- 到 GND */
int32_t adc_measure_offset(ADC_HandleTypeDef *hadc,
                           uint16_t *result,
                           uint8_t count) {
    uint32_t sum = 0;
    uint16_t raw;
    int i;
    HAL_ADC_Stop(hadc);
    hadc->Instance->CR |= ADC_CR_ADCAL;
    while (hadc->Instance->CR & ADC_CR_ADCAL) {}
    HAL_Delay(1);
    HAL_ADC_Start(hadc);
    for (i = 0; i < count; i++) {
        HAL_ADC_PollForConversion(hadc, HAL_MAX_DELAY);
        raw = HAL_ADC_GetValue(hadc);
        sum += raw;
    }
    HAL_ADC_Stop(hadc);
    *result = (uint16_t)(sum / count);
    return HAL_OK;
}

/* 采样 + 偏移修正 + 饱和截断 */
uint16_t adc_sample_offset(ADC_HandleTypeDef *hadc) {
    uint16_t raw;
    int32_t corrected;
    HAL_ADC_StartPoll(hadc);
    HAL_ADC_PollForConversion(hadc, HAL_MAX_DELAY);
    raw = HAL_ADC_GetValue(hadc);
    corrected = (int32_t)raw - g_offset_calib;
    if (corrected < 0) corrected = 0;
    if (corrected > ADC_REF_VALUE) corrected = ADC_REF_VALUE;
    return (uint16_t)corrected;
}

/* 诊断代码：检测采样质量 */
/* 通过连续采样统计方差来判断噪声水平 */

#include <stdint.h>
#include <string.h>

#define SAMPLE_COUNT 256
#define GOOD_THRESH  4U

typedef struct {
    uint32_t variance;
    uint16_t min_val;
    uint16_t max_val;
} adc_quality_report_t;

uint32_t adc_var(uint16_t *buf, uint32_t len) {
    uint32_t sum = 0, sum_sq = 0, i;
    for (i = 0; i < len; i++) {
        sum += buf[i];
        sum_sq += buf[i] * buf[i];
    }
    uint32_t mean = sum / len;
    return (sum_sq / len) - (mean * mean);
}

adc_quality_report_t adc_check(uint16_t *samples,
                               uint32_t count) {
    adc_quality_report_t r;
    uint32_t i;
    memset(&r, 0, sizeof(r));
    if (count > SAMPLE_COUNT) count = SAMPLE_COUNT;
    r.min_val = 0xFFFF;
    r.max_val = 0;
    for (i = 0; i < count; i++) {
        if (samples[i] < r.min_val)
            r.min_val = samples[i];
        if (samples[i] > r.max_val)
            r.max_val = samples[i];
    }
    r.variance = adc_var(samples, count);
    return r;
}

/* ❌ 改进前：移动平均 - 消耗大量 RAM 和 CPU */

#define FILTER_WINDOW 256
static uint16_t ring_buf[FILTER_WINDOW];
static uint8_t  ring_idx = 0;
static uint8_t  cnt = 0;

uint16_t filter_ma(uint16_t sample) {
    ring_buf[ring_idx] = sample;
    ring_idx = (ring_idx + 1) % FILTER_WINDOW;
    if (cnt < FILTER_WINDOW) cnt++;
    uint32_t sum = 0;
    uint8_t i;
    for (i = 0; i < cnt; i++) {
        sum += ring_buf[i];
    }
    return (uint16_t)(sum / cnt);
}

/* ✅ 改进后：指数移动平均 - O(1) 时空 */

#define EMA_SHIFT 4
static uint32_t ema_acc = 0;
static uint8_t  ema_init = 0;

uint16_t filter_ema(uint16_t sample) {
    uint32_t scaled;
    uint32_t prev;
    if (!ema_init) {
        ema_acc = (uint32_t)sample << EMA_SHIFT;
        ema_init = 1;
        return sample;
    }
    scaled = (uint32_t)sample << EMA_SHIFT;
    prev = ema_acc;
    ema_acc = scaled + (prev - (prev >> EMA_SHIFT));
    return (uint16_t)(ema_acc >> EMA_SHIFT);
}
